{
  "domain_analysis": {
    "business_context": "A courier-tracking feature is being specified for customer-facing delivery visibility. Two internal stakeholder teams have submitted directly contradictory requirements regarding whether courier GPS location should be shown to customers during delivery.",
    "bounded_context": "Delivery Tracking / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Courier", "definition": "The driver or delivery person fulfilling a delivery order" },
      { "term": "Real-time location", "definition": "GPS coordinates of the courier updated on a continuous or near-continuous basis during an active delivery" },
      { "term": "Delivery window", "definition": "The time period during which a delivery is in transit from pickup to dropoff" },
      { "term": "Customer", "definition": "The end recipient of the delivery who is waiting for the order" },
      { "term": "Delivery visibility", "definition": "The degree to which a customer can observe the progress and location of their in-transit delivery" }
    ]
  },

  "business_rules": [],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "Courier is stationary for extended period (e.g., traffic, break) and customer sees no movement", "expected_behavior": "Undefined — depends on resolution of core conflict. If location is shown, stationary couriers generate support calls. If abstracted, this is less visible." },
    { "scenario": "Courier deviates significantly from expected route", "expected_behavior": "Undefined — exact GPS exposes this; abstracted ETA hides it. Both have customer trust implications." },
    { "scenario": "Courier is near customer's home but delivering another order first (multi-stop route)", "expected_behavior": "Undefined — exact GPS would show courier 'passing by' the customer, generating complaints. Abstracted status avoids this." },
    { "scenario": "GPS signal lost or inaccurate in urban canyon / parking garage", "expected_behavior": "Undefined — stale exact coordinates are misleading; abstracted ETA is more resilient to signal gaps." },
    { "scenario": "Courier ends shift or reassignment happens mid-delivery", "expected_behavior": "Undefined — exact tracking of the original courier becomes meaningless; status-based tracking transitions more gracefully." }
  ],

  "business_impact": {
    "financial": "Direct revenue risk in both directions. Losing couriers (Operations concern) increases recruitment/training costs and reduces delivery capacity, directly constraining revenue. Losing customer trust (Customer Success concern) increases churn and reduces order volume. Neither team's position can be dismissed without quantified data on courier attrition rates vs. customer satisfaction/retention metrics.",
    "operational": "Courier retention is an existential operational constraint — without drivers, there is no delivery service. Customer visibility is a competitive differentiator but is not the sole determinant of customer retention. The supply side (couriers) is typically harder to replace than the demand side (customers) in two-sided logistics marketplaces.",
    "user": "Two distinct user groups with opposing needs: customers want maximum transparency; couriers want privacy and dignity. Any solution must serve both sides of the marketplace.",
    "risk": "HIGH. Implementing either team's requirement as stated will directly harm the other team's core metric. There is also regulatory risk: sharing exact courier GPS coordinates may implicate privacy regulations (GDPR, state privacy laws) depending on jurisdiction. Courier location data is personal data in many legal frameworks.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Delivery visibility affects trust, anxiety during wait, and perceived service quality" },
      { "group": "Couriers", "impact": "Location sharing affects sense of surveillance, autonomy, job satisfaction, and retention" },
      { "group": "Customer Success team", "impact": "Their NPS and satisfaction KPIs depend on transparency features" },
      { "group": "Operations team", "impact": "Their courier retention and supply-side health KPIs are threatened by surveillance perception" },
      { "group": "Legal/Compliance", "impact": "NOT YET CONSULTED — courier GPS sharing has privacy regulation implications that neither team has addressed" },
      { "group": "Executive leadership", "impact": "Must arbitrate this conflict as it represents a fundamental product strategy tension between supply-side and demand-side priorities" }
    ]
  },

  "confidence": {
    "level": 25,
    "reasoning": "Confidence is critically low because the two authoritative stakeholder teams have issued directly contradictory hard requirements. This is not a technical ambiguity — it is a business strategy conflict that cannot be resolved by engineering or domain analysis alone. It requires executive arbitration. Additionally, Legal/Compliance has not been consulted on what may be a regulated decision. No quantified data has been provided on courier attrition rates or customer satisfaction impact to inform a rational tradeoff.",
    "high_confidence_areas": [
      "The two requirements as stated are genuinely contradictory and cannot both be satisfied simultaneously",
      "Courier location data is personal data with privacy regulation implications",
      "Supply-side (courier) retention is typically the harder constraint in two-sided delivery marketplaces",
      "There exist well-known industry compromise patterns (abstracted ETAs, zone-based tracking) that neither team has considered"
    ],
    "low_confidence_areas": [
      "Which business priority actually dominates — we lack data on courier attrition vs. customer churn",
      "Whether legal/regulatory constraints exist that would make this decision for us",
      "Whether either team would accept a compromise solution or if positions are truly non-negotiable",
      "What competitor landscape looks like — is exact tracking truly a differentiator or table stakes"
    ],
    "assumptions": [
      "Both teams are acting in good faith and representing real business concerns, not positional bargaining",
      "There is no existing executive decision or company policy that already resolves this conflict",
      "The company operates in jurisdictions where courier GPS privacy may be regulated"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "Customer Success requires 'exact GPS coordinates at all times' while Operations requires 'location must never be shown.' These are binary opposites — one says always, the other says never. No engineering solution can satisfy both requirements as stated. This is a business strategy decision about whether the company prioritizes demand-side transparency or supply-side retention.",
      "affected_stakeholders": ["Customers", "Couriers", "Customer Success team", "Operations team", "Executive leadership"],
      "options": [
        "A: Side with Customer Success — show exact GPS. Accept courier attrition risk. Mitigate with courier compensation or consent mechanisms.",
        "B: Side with Operations — hide location entirely. Accept reduced customer transparency. Mitigate with better ETA accuracy and proactive notifications.",
        "C: Compromise — show abstracted location (zone-based, e.g., '3 stops away' or 'arriving in ~5 min') that gives customers useful visibility without making couriers feel surveilled. This is the industry-standard pattern used by most major delivery platforms.",
        "D: Courier-consent model — let couriers opt in/out of location sharing, with incentives for opting in. Customers see location only when courier consents."
      ],
      "recommendation": "Option C. The industry has largely converged on abstracted delivery progress (ETA-based, zone-based, or stage-based like 'picked up → on the way → nearby → arriving') precisely because it resolves this exact tension. Exact GPS coordinates are not what customers actually need — they need to know WHEN the delivery arrives, not WHERE the courier is right now. Abstracted tracking satisfies the real customer need (reduce delivery anxiety) without creating the surveillance dynamic that drives courier attrition. However, this is a BUSINESS DECISION that must be made by executive leadership, not by engineering. I am flagging this for immediate escalation."
    },
    {
      "type": "missing_context",
      "description": "Legal/Compliance has not been consulted. Sharing a courier's exact real-time GPS coordinates with third parties (customers) may violate privacy regulations (GDPR Article 6/9, CCPA, state biometric/location privacy laws) and may require explicit courier consent regardless of business preference. This could make the decision for us.",
      "affected_stakeholders": ["Legal/Compliance", "Couriers", "Executive leadership"],
      "options": [
        "Engage Legal/Compliance for a privacy impact assessment before any implementation decision",
        "Proceed without legal review and accept regulatory risk"
      ],
      "recommendation": "Engage Legal/Compliance immediately. If regulations require courier consent for exact location sharing, Option D or Option C become the only viable paths regardless of stakeholder preferences."
    }
  ],

  "rejection_reasons": [
    { "violation": "Cannot implement 'show exact GPS at all times' as specified by Customer Success", "business_rule_broken": "Directly contradicted by Operations requirement and unsupported by privacy/legal review" },
    { "violation": "Cannot implement 'never show location' as specified by Operations", "business_rule_broken": "Directly contradicted by Customer Success requirement and would eliminate a competitive feature" },
    { "violation": "Cannot proceed to acceptance criteria or implementation", "business_rule_broken": "Fundamental stakeholder contradiction must be resolved by executive decision before any specification work can begin" }
  ]
}

